member.example:
Bind the Renderer material property using a serialized binder field — the target Renderer is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private RendererMaterialsBinder _material;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Material _material;
    }


Bind the Renderer material property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private Renderer _renderer;
        
        private RendererMaterialsBinder Material =>
            new(_renderer);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public Material _material;
    }

Switch the Renderer materials array between two values using a serialized binder field — the target Renderer is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private RendererMaterialsSwitcherBinder _isHighlighted;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighlighted;
    }


Switch the Renderer materials array between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private Renderer _renderer;
        
        [SerializeField]
        private Material[] _highlightedMaterials;
        
        [SerializeField]
        private Material[] _defaultMaterials;
        
        private RendererMaterialsSwitcherBinder IsHighlighted => new(
            _renderer, _highlightedMaterials, _defaultMaterials);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighlighted;
    }
